// EasyToLearn — embedded icon (base64 so it works without a server)
window.ETL_ICON = "data:image/png;base64,";

// Apply icon to all .brand-badge img and .icon-img elements
document.addEventListener("DOMContentLoaded", function() {
  document.querySelectorAll('img[data-icon="etl"]').forEach(function(img) {
    img.src = window.ETL_ICON;
  });
});
